export default function DarkModeToggle({ value, onChange }) {
  return (
    <button
      onClick={() => onChange(!value)}
      aria-pressed={value}
      style={{
        display: 'inline-flex', alignItems: 'center', gap: 8,
        padding: '10px 18px', borderRadius: 999, cursor: 'pointer',
        border: '1px solid ' + (value ? '#334155' : '#cbd5e1'),
        background: value ? '#1e293b' : '#f1f5f9',
        color: value ? '#e2e8f0' : '#111', fontSize: 15, fontWeight: 600,
      }}
    >
      <span>{value ? '\u{1F319}' : '\u2600\uFE0F'}</span>
      {value ? 'Dark' : 'Light'}
    </button>
  );
}

files./App.js:
import { useState, useEffect } from 'react';
import DarkModeToggle from './src/DarkModeToggle';

export default function App() {
  const [dark, setDark] = useState(() => {
    try { return localStorage.getItem('theme') === 'dark'; } catch { return false; }
  });

  useEffect(() => {
    try { localStorage.setItem('theme', dark ? 'dark' : 'light'); } catch {}
  }, [dark]);

  return (
    <div style={{
      minHeight: '100vh', fontFamily: 'system-ui, sans-serif', padding: 40, textAlign: 'center',
      background: dark ? '#0f172a' : '#ffffff', color: dark ? '#e2e8f0' : '#111111',
      transition: 'background 0.3s, color 0.3s',
    }}>
      <h2>Dark Mode Toggle</h2>
      <p style={{ opacity: 0.7 }}>Your preference is saved to localStorage.</p>
      <DarkModeToggle value={dark} onChange={setDark} />
      <p style={{ marginTop: 20 }}>Theme: <strong>{dark ? 'dark' : 'light'}</strong></p>
    </div>
  );
}

angular.answer:
In Angular the dark-mode toggle is a single `dark` field; bind colors with **style bindings** and persist to `localStorage`.

### Step 1 — State + restore

Read the saved theme in the constructor (guard with try/catch).

```ts
dark = false;
constructor() {
  try { this.dark = localStorage.getItem('theme') === 'dark'; } catch (e) {}
}
```

### Step 2 — Toggle + persist

```ts
toggle() {
  this.dark = !this.dark;
  try { localStorage.setItem('theme', this.dark ? 'dark' : 'light'); } catch (e) {}
}
```

### Step 3 — Apply with style bindings

`[style.background]` / `[style.color]` flip from the `dark` flag; a CSS `transition` smooths it.

**Interview tip:** the Angular bits are **`[style.background]` bindings** driven by one boolean and persistence in the constructor/toggle. Avoid `ngModel` here — a plain `(click)` toggle is simpler.

