import { Component } from '@angular/core';

@Component({
  selector: 'app-root',
  template: `
    <div
      [style.background]="dark ? '#0f172a' : '#ffffff'"
      [style.color]="dark ? '#e2e8f0' : '#111111'"
      style="min-height:100vh; font-family: system-ui, sans-serif; padding:40px; text-align:center; transition: background 0.3s, color 0.3s">
      <h2>Dark Mode Toggle</h2>
      <p style="opacity:0.7">Your preference is saved to localStorage.</p>
      <button
        (click)="toggle()"
        [attr.aria-pressed]="dark"
        [style.background]="dark ? '#1e293b' : '#f1f5f9'"
        [style.color]="dark ? '#e2e8f0' : '#111'"
        [style.border]="'1px solid ' + (dark ? '#334155' : '#cbd5e1')"
        style="padding:10px 18px; border-radius:999px; cursor:pointer; font-size:15px; font-weight:600">
        {{ dark ? '\u{1F319} Dark' : '\u2600\uFE0F Light' }}
      </button>
      <p style="margin-top:20px">Theme: <strong>{{ dark ? 'dark' : 'light' }}</strong></p>
    </div>
  `,
})
export class AppComponent {
  dark = false;

  constructor() {
    try {
      this.dark = localStorage.getItem('theme') === 'dark';
    } catch (e) {}
  }

  toggle() {
    this.dark = !this.dark;
    try {
      localStorage.setItem('theme', this.dark ? 'dark' : 'light');
    } catch (e) {}
  }
}
